sql:
SELECT experiment_id, COUNT(*) AS num_researchers
FROM experiment_researchers
GROUP BY experiment_id;

SELECT AVG(visual_frequency) 
FROM trials 
WHERE haptic_index = (SELECT MAX(haptic_index) FROM trials);

SELECT COUNT(*) 
FROM phases 
WHERE experiment_id = 5;

SELECT DISTINCT r.researcher_name 
FROM researchers r 
JOIN experiment_researchers er ON r.researcher_id = er.researcher_id;

external_knowledge:
- 'experimental projects' refers to 'experiments';
- 'leaders' refers to 'principal investigators';
- 'approximate workforce size' means the count of distinct researchers;
- 'projects with no contributors' are those with a researcher count of 0.
